import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionSecure {

    public static void main(String[] args) {
        try {
            // Simulating user input
            String userInput = "test.txt; ls -la";

            // Sanitize user input by splitting it and only taking the first part
            String[] parts = userInput.split(" ");
            String sanitizedInput = parts[0];

            // Secure code using ProcessBuilder
            ProcessBuilder processBuilder = new ProcessBuilder();
            processBuilder.command("cat", sanitizedInput);

            Process process = processBuilder.start();

            BufferedReader reader =
                    new BufferedReader(new InputStreamReader(process.getInputStream()));

            String line;

            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

